#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use URI::Escape;

my $cgi = new CGI;
my $redirect_url = $cgi->param('next');

if ($redirect_url && $redirect_url =~ /^https?:\/\//) {
    $redirect_url = uri_unescape($redirect_url);
    print $cgi->redirect($redirect_url);
} else {
